sql:
SELECT p.title
FROM papers p
WHERE p.status = 'under review' AND p.final_decision IS NULL;

SELECT DISTINCT p.*
FROM papers p
INNER JOIN paper_reviewers pr ON p.paper_id = pr.paper_id;

SELECT DISTINCT a.first_name, a.last_name
FROM papers p
INNER JOIN authors a ON p.author_id = a.author_id;

SELECT DISTINCT p.title, p.abstract
FROM papers p
JOIN conflicts_of_interest coi ON p.paper_id = coi.paper_id;

external_knowledge:
- "Seasoned sailers": Refers to experienced reviewers in the academic community;
- "Navigating the seas of scholarly discourse": Metaphor for the process of evaluating academic papers;
- "Voyages": Refers to the reviews conducted by the reviewers;
- "Successfully found their harbor": Indicates papers that have been accepted;
- "Warm and favorable light": Implies an average rating greater than 3.5, indicating positive reviews;
- "Dozen and a half": Refers to a count greater than 15.

sql:
SELECT AVG(author_count) AS average_author_count
FROM (
  SELECT paper_id, COUNT(author_id) AS author_count
  FROM paper_authors
  GROUP BY paper_id
) AS paper_author_counts;

SELECT papers.*, conflicts_of_interest.*
FROM papers
INNER JOIN conflicts_of_interest ON papers.paper_id = conflicts_of_interest.paper_id;

SELECT p.title, p.author_id, p.status, p.final_decision 
FROM papers p
INNER JOIN conflicts_of_interest coi ON p.paper_id = coi.paper_id;

SELECT DISTINCT re.first_name
FROM reviews r
JOIN reviewers re ON r.reviewer_id = re.reviewer_id;

SELECT paper_id
FROM papers
WHERE final_decision = 'rejected';
